"""
Workflow data transformation module for processing step outputs.
"""
import ast
import operator


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string safely.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression contains unsafe syntax or fails to evaluate to a dict.
    """

    # Define allowed operators for arithmetic, comparison, and logic
    allowed_operators = {
        # Arithmetic
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        # Unary
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
        # Comparison
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.In: lambda a, b: a in b,
        ast.NotIn: lambda a, b: a not in b,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        # Literals (Python 3.8+ uses Constant for all literals)
        if isinstance(node, ast.Constant):
            return node.value

        # Literals (Support for older Python 3 versions)
        if isinstance(node, (ast.Num, ast.Str, ast.Bytes, ast.NameConstant)):
            return getattr(node, 'n', getattr(node, 's', getattr(node, 'value', None)))

        # Variables: Only allow 'input_data'
        if isinstance(node, ast.Name):
            if node.id == 'input_data':
                return input_data
            raise ValueError(f"Access to name '{node.id}' is not allowed")

        # Dictionary, List, and Tuple literals
        if isinstance(node, ast.Dict):
            return { _eval(k): _eval(v) for k, v in zip(node.keys, node.values) }
        if isinstance(node, ast.List):
            return [ _eval(e) for e in node.elts ]
        if isinstance(node, ast.Tuple):
            return tuple( _eval(e) for e in node.elts )

        # Binary Operations (+, -, *, etc.)
        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type in allowed_operators:
                return allowed_operators[op_type](_eval(node.left), _eval(node.right))
            raise ValueError(f"Unsupported binary operator: {op_type.__name__}")

        # Unary Operations (not, -x)
        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type in allowed_operators:
                return allowed_operators[op_type](_eval(node.operand))
            raise ValueError(f"Unsupported unary operator: {op_type.__name__}")

        # Logical Operations (and, or) with short-circuiting
        if isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                res = None
                for v in node.values:
                    res = _eval(v)
                    if not res:
                        return res
                return res
            if isinstance(node.op, ast.Or):
                res = None
                for v in node.values:
                    res = _eval(v)
                    if res:
                        return res
                return res

        # Comparisons (==, !=, <, >, in, etc.)
        if isinstance(node, ast.Compare):
            left = _eval(node.left)
            for op, right_node in zip(node.ops, node.comparators):
                right = _eval(right_node)
                op_type = type(op)
                if op_type in allowed_operators:
                    if not allowed_operators[op_type](left, right):
                        return False
                    left = right
                else:
                    raise ValueError(f"Unsupported comparison operator: {op_type.__name__}")
            return True

        # Subscripting (e.g., input_data['id'])
        if isinstance(node, ast.Subscript):
            container = _eval(node.value)
            # Handle slice for different Python versions (ast.Index was deprecated in 3.9)
            if hasattr(ast, 'Index') and isinstance(node.slice, ast.Index):
                index = _eval(node.slice.value)
            else:
                index = _eval(node.slice)
            return container[index]

        # Slicing (e.g., input_data['items'][0:5])
        if isinstance(node, ast.Slice):
            return slice(
                _eval(node.lower) if node.lower else None,
                _eval(node.upper) if node.upper else None,
                _eval(node.step) if node.step else None
            )

        raise ValueError(f"Unsupported expression component: {type(node).__name__}")

    try:
        # Parse the expression string into an AST
        tree = ast.parse(transform_map_expr.strip(), mode='eval')
        result = _eval(tree)
    except Exception as e:
        # Wrap internal errors to provide a clean interface
        raise ValueError(f"Invalid transformation expression: {e}")

    if not isinstance(result, dict):
        raise ValueError("The transformation expression must evaluate to a dictionary.")

    return result
